Javascript.validate:
var val = Services.getValue(SinglePaymentAmnt.dataBinding);
var err  = WPU.validateCurrency(val);
if( null == err )
{	Services.setValue(SinglePaymentAmnt.dataBinding, WPU.formatToTwoDP(val));
}
return err;

